"""
Sample 11: Catching specific exceptions
"""

import json


def read_config(path: str) -> dict:
    """Read a JSON config file. Returns empty dict on expected failures."""
    try:
        with open(path) as f:
            return json.load(f)
    except (FileNotFoundError, json.JSONDecodeError):
        return {}


def main() -> None:
    config = read_config("/nonexistent/config.json")
    port = config.get("port", 8080)
    print(f"Starting on port {port}")
